import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux'; // Hooked up for global access readiness
import './CategoryPage.css';

// ── BACKEND SIMULATION DATA MODELS (Prepared for Redux / Universal Application State) ──
const BACKEND_BANNERS = [
  { src: 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?auto=format&fit=crop&w=1200&q=80', alt: 'Software Engineering Services' },
  { src: 'https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&w=1200&q=80', alt: 'Innovative Tech Space' },
];

const BACKEND_LISTINGS = [
  {
    id: 1,
    name: 'Gv Solutions',
    rating: 5.0,
    ratingCount: 6,
    topTag: 'Top Search',
    location: 'Madurai Main',
    distance: 1.2, // in km
    popularity: 98,
    years: '12 Years in Business',
    tags: ['Software Companies', 'Online Websites'],
    phone: '08460506156',
    img: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=400',
    isVerified: true,
    isTrust: true
  },
  {
    id: 2,
    name: 'TechNest Systems',
    rating: 4.8,
    ratingCount: 14,
    topTag: 'JD Verified',
    location: 'Anna Nagar, Madurai',
    distance: 3.5,
    popularity: 85,
    years: '8 Years in Business',
    tags: ['Mobile Apps', 'Web Design'],
    phone: '09876543210',
    img: 'https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&w=400',
    isVerified: true,
    isTrust: false
  },
  {
    id: 3,
    name: 'PixelForge Studio',
    rating: 4.5,
    ratingCount: 9,
    topTag: null,
    location: 'KK Nagar, Madurai',
    distance: 0.8,
    popularity: 72,
    years: '5 Years in Business',
    tags: ['UI/UX Design', 'Branding'],
    phone: '07890123456',
    img: 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?auto=format&fit=crop&w=400',
    isVerified: false,
    isTrust: true
  },
  {
    id: 4,
    name: 'Apex Digital Systems',
    rating: 4.2,
    ratingCount: 22,
    topTag: 'Popular',
    location: 'Simmakkal, Madurai',
    distance: 4.1,
    popularity: 91,
    years: '10 Years in Business',
    tags: ['Cloud Computing', 'ERP Software'],
    phone: '09441234567',
    img: 'https://images.unsplash.com/photo-1551434678-e076c223a692?auto=format&fit=crop&w=400',
    isVerified: true,
    isTrust: true
  }
];

const BACKEND_RELATED_CATEGORIES = [
  { id: 'rel-1', name: 'Web Designers in Madurai', count: '142 options' },
  { id: 'rel-2', name: 'Mobile App Developers', count: '98 options' },
  { id: 'rel-3', name: 'Digital Marketing Agencies', count: '210 options' },
  { id: 'rel-4', name: 'IT Training Institutes', count: '65 options' },
  { id: 'rel-5', name: 'SEO Consultants', count: '43 options' }
];

const BACKEND_ADS = [
  {
    id: 'ad-pos-1',
    insertAfterIndex: 1, // Will show up after the first card
    title: 'Upgrade to Premium Enterprise Cloud Storage',
    content: 'Get 2TB high-speed redundant storage for your agency. 50% discount for local Madurai enterprises this month.',
    img: 'https://images.unsplash.com/photo-1544197150-b99a580bb7a8?auto=format&fit=crop&w=400',
    cta: 'Claim Offer'
  },
  {
    id: 'ad-pos-2',
    insertAfterIndex: 3, // Will show up after the third card
    title: 'Hire Certified Remote Developers Instantly',
    content: 'Vetted React and Node.js professionals ready to scale your local operation within 48 hours.',
    img: 'https://images.unsplash.com/photo-1531403009284-440f080d1e12?auto=format&fit=crop&w=400',
    cta: 'Learn More'
  }
];

// ── LAZY-LOAD VIEWPORT WRAPPER COMPONENT ──
function LazyViewElement({ children, onVisible }) {
  const elementRef = useRef(null);
  const [hasLoaded, setHasLoaded] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setHasLoaded(true);
          if (onVisible) onVisible();
          observer.disconnect();
        }
      },
      { rootMargin: '50px' }
    );

    if (elementRef.current) {
      observer.observe(elementRef.current);
    }

    return () => observer.disconnect();
  }, [onVisible]);

  return (
    <div ref={elementRef} className={`lazy-element-container ${hasLoaded ? 'loaded' : 'is-loading'}`}>
      {hasLoaded ? children : <div className="backend-lazy-skeleton">Loading Content Component...</div>}
    </div>
  );
}

// ── INTERACTIVE DISMISSIBLE AD CARD MODULE ──
function AdCard({ ad, onClose }) {
  return (
    <div className="advertisement-card-container">
      <button className="ad-close-trigger" onClick={onClose} aria-label="Close Ad">
        <i className="fa-solid fa-xmark"></i>
      </button>
      <div className="ad-badge-label">Sponsored Announcement</div>
      <div className="ad-card-inner-layout">
        {ad.img && (
          <div className="ad-graphics-frame">
            <img src={ad.img} alt={ad.title} />
          </div>
        )}
        <div className="ad-copywritten-content">
          <h4 className="ad-marketing-title">{ad.title}</h4>
          <p className="ad-body-text">{ad.content}</p>
          <button className="ad-cta-action-btn">{ad.cta}</button>
        </div>
      </div>
    </div>
  );
}

// ── BANNER COMPONENT WITH REMOVED OVERLAY ──
function CategoryBanner({ banners }) {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    if (!banners || banners.length === 0) return;
    const t = setInterval(() => setCurrent((c) => (c + 1) % banners.length), 6000);
    return () => clearInterval(t);
  }, [banners]);

  return (
    <div className="category-banner">
      {banners.map((b, i) => (
        <div key={i} className={`category-banner-slide${i === current ? ' active' : ''}`}>
          <img src={b.src} alt={b.alt} />
        </div>
      ))}
      <div className="category-banner-heading-dock">
        <h2 className="banner-heading-text-dark">Software Companies in Madurai</h2>
      </div>
    </div>
  );
}

// ── MAIN EXPORT COMPONENT ──
export default function CategoryPage() {
  const navigate = useNavigate();

  // Unified State Stores (Populated locally, matching global Redux design structures)
  const [banners, setBanners] = useState([]);
  const [listings, setListings] = useState([]);
  const [relatedCategories, setRelatedCategories] = useState([]);
  const [activeAds, setActiveAds] = useState([]);
  const [dismissedAdIds, setDismissedAdIds] = useState([]);

  // Live Filtering & Sorting Evaluation States
  const [sortBy, setSortBy] = useState('relevance'); // relevance, rating, popular, distance
  const [filterVerified, setFilterVerified] = useState(true); // Default active as per standard layout state
  const [filterTrust, setFilterTrust] = useState(false);
  const [showSortDropdown, setShowSortDropdown] = useState(false);

  // Lazy Initialization Hooks simulating backend collection fetching
  const triggerLazyBannerFetch = () => { if (banners.length === 0) setBanners(BACKEND_BANNERS); };
  const triggerLazyListingFetch = () => { if (listings.length === 0) setListings(BACKEND_LISTINGS); };
  const triggerLazySidebarFetch = () => {
    if (relatedCategories.length === 0) {
      setRelatedCategories(BACKEND_RELATED_CATEGORIES);
      setActiveAds(BACKEND_ADS);
    }
  };

  const handleDismissAd = (adId) => {
    setDismissedAdIds((prev) => [...prev, adId]);
  };

  // ── LIVE FILTER / SORT ENGINE RUNTIME LOGIC ──
  const getProcessedListings = () => {
    let output = [...listings];

    // Evaluate Filter Checkboxes
    if (filterVerified) {
      output = output.filter(item => item.isVerified);
    }
    if (filterTrust) {
      output = output.filter(item => item.isTrust);
    }

    // Evaluate Sorting Modifiers
    if (sortBy === 'rating') {
      output.sort((a, b) => b.rating - a.rating);
    } else if (sortBy === 'popular') {
      output.sort((a, b) => b.popularity - a.popularity);
    } else if (sortBy === 'distance') {
      output.sort((a, b) => a.distance - b.distance);
    } else {
      // Relevance fallback default sorting structure
      output.sort((a, b) => b.id - a.id);
    }

    return output;
  };

  const processedListings = getProcessedListings();

  return (
    <div className="category-page">
      {/* Dynamic Banner Section */}
      <LazyViewElement onVisible={triggerLazyBannerFetch}>
        <CategoryBanner banners={banners} />
      </LazyViewElement>

      <div className="container category-layout">
        <div className="row">

          {/* Left Column Layout: Main Listings Content Feed */}
          <div className="col-lg-8 category-main">
            <div className="breadcrumb-nav">
              Madurai &gt; Software Companies in Madurai &gt; <span>{processedListings.length}+ Listings Verified</span>
            </div>

            <h1 className="category-page-title">
              Innovative Solutions: Top Software Companies in Madurai
            </h1>

            {/* Live Interactive Control Context Bar */}
            <div className="filter-chips">
              <div className="sort-dropdown-wrapper">
                <button 
                  className={`filter-chip ${sortBy !== 'relevance' ? 'active-chip' : ''}`}
                  onClick={() => setShowSortDropdown(!showSortDropdown)}
                >
                  Sort by: <span className="current-sort-label">{sortBy.toUpperCase()}</span>{' '}
                  <i className="fa fa-chevron-down" style={{ fontSize: '0.65rem' }}></i>
                </button>

                {showSortDropdown && (
                  <div className="sort-interactive-select-panel">
                    <div className={`sort-option ${sortBy === 'relevance' ? 'selected' : ''}`} onClick={() => { setSortBy('relevance'); setShowSortDropdown(false); }}>Relevance</div>
                    <div className={`sort-option ${sortBy === 'rating' ? 'selected' : ''}`} onClick={() => { setSortBy('rating'); setShowSortDropdown(false); }}>Highest Rating</div>
                    <div className={`sort-option ${sortBy === 'popular' ? 'selected' : ''}`} onClick={() => { setSortBy('popular'); setShowSortDropdown(false); }}>Popularity Metric</div>
                    <div className={`sort-option ${sortBy === 'distance' ? 'selected' : ''}`} onClick={() => { setSortBy('distance'); setShowSortDropdown(false); }}>Proximity (Distance)</div>
                  </div>
                )}
              </div>

              <button 
                className={`filter-chip ${filterVerified ? 'active-chip' : ''}`}
                onClick={() => setFilterVerified(!filterVerified)}
              >
                {filterVerified && <i className="fa fa-check-circle"></i>} JD Verified
              </button>

              <button 
                className={`filter-chip ${filterTrust ? 'active-chip' : ''}`}
                onClick={() => setFilterTrust(!filterTrust)}
              >
                {filterTrust && <i className="fa fa-check-circle"></i>} <i className="fa fa-crown" style={{ marginRight: '4px' }}></i> JD Trust
              </button>
            </div>

            {/* Interwoven Listing Card Feed Engine */}
            <LazyViewElement onVisible={triggerLazyListingFetch}>
              {processedListings.length === 0 ? (
                <div className="empty-results-fallback">
                  <i className="fa-solid fa-filter-circle-xmark"></i>
                  <p>No companies match your current toggle criteria. Try loosening your filter choices.</p>
                </div>
              ) : (
                processedListings.map((item, index) => {
                  const elementsToRender = [];

                  // Inject Listing Card
                  elementsToRender.push(
                    <div key={`listing-${item.id}`} className="listing-card">
                      <div className="listing-img">
                        <img src={item.img} alt={item.name} />
                      </div>

                      <div className="listing-info">
                        <div className="listing-name">
                          <i className="fa-solid fa-thumbs-up"></i>
                          {item.name}
                        </div>

                        <div className="listing-rating-row">
                          <span className="rating-badge">{item.rating.toFixed(1)}</span>
                          <span className="rating-count">{item.ratingCount} Ratings</span>
                          {item.topTag && <span className="tag-top-search">{item.topTag}</span>}
                          <span className="proximity-geo-tag">
                            <i className="fa-solid fa-route"></i> {item.distance} km away
                          </span>
                        </div>

                        <div className="listing-meta">
                          <span><i className="fa-solid fa-location-dot"></i> {item.location}</span>
                          <span><i className="fa-solid fa-briefcase"></i> {item.years}</span>
                        </div>

                        <div className="listing-tags">
                          {item.tags.map((t) => (
                            <span key={t} className="listing-tag">{t}</span>
                          ))}
                        </div>

                        <div className="listing-actions">
                          <a href={`tel:${item.phone}`} className="btn-call" style={{ textDecoration: 'none' }}>
                            <i className="fa-solid fa-phone"></i> {item.phone}
                          </a>
                          <button className="btn-whatsapp">
                            <i className="fa-brands fa-whatsapp"></i> WhatsApp
                          </button>
                          <button className="btn-price" onClick={() => navigate('/company')}>
                            Get Best Price
                          </button>
                        </div>
                      </div>
                    </div>
                  );

                  // Evaluate and Inject Ad Card positioned sequentially after specific indices
                  const matchingAd = activeAds.find(ad => ad.insertAfterIndex === index && !dismissedAdIds.includes(ad.id));
                  if (matchingAd) {
                    elementsToRender.push(
                      <AdCard 
                        key={`ad-${matchingAd.id}`} 
                        ad={matchingAd} 
                        onClose={() => handleDismissAd(matchingAd.id)} 
                      />
                    );
                  }

                  return elementsToRender;
                })
              )}
            </LazyViewElement>
          </div>

          {/* Right Column Layout: Fixed/Sticky Sidebar Shell Layout */}
          <div className="col-lg-4 category-sidebar">
            <LazyViewElement onVisible={triggerLazySidebarFetch}>
              <div className="sidebar-sticky-enclosure">

                {/* Requirements Module Section */}
                <div className="sidebar-card">
                  <h3 className="sidebar-title">
                    Get the List of Top <span>Software Companies</span>
                  </h3>
                  <p className="sidebar-subtitle">We'll send you verified options instantly.</p>

                  <input className="sidebar-input" type="text" placeholder="Your Name" aria-label="Your Name" />
                  <input className="sidebar-input" type="tel" placeholder="Mobile Number" aria-label="Mobile Number" />
                  <input className="sidebar-input" type="text" placeholder="Your Location" aria-label="Your Location" />

                  <button className="sidebar-submit">Send My Requirements</button>
                </div>

                {/* Related Categories Navigation Segment */}
                <div className="related-categories-card-box">
                  <h3 className="sidebar-title context-dark-color">Related Categories</h3>
                  <p className="sidebar-subtitle">Explore alternative service paths in Madurai</p>

                  <div className="related-categories-vertical-stack">
                    {relatedCategories.map((cat) => (
                      <div key={cat.id} className="related-category-row-item" onClick={() => navigate('/category')}>
                        <div className="related-cat-info">
                          <span className="related-cat-name-link">{cat.name}</span>
                          <span className="related-cat-metric-label">{cat.count}</span>
                        </div>
                        <i className="fa-solid fa-chevron-right related-cat-arrow"></i>
                      </div>
                    ))}
                  </div>
                </div>

              </div>
            </LazyViewElement>
          </div>

        </div>
      </div>
    </div>
  );
}
